// ─── Hooks ────────────────────────────────────────────────────────────────────
function useInView(threshold = 0.1) {
  const ref = useRef(null);
  const [v, setV] = useState(false);
  useEffect(() => {
    const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setV(true); o.disconnect(); } }, { threshold });
    if (ref.current) o.observe(ref.current);
    return () => o.disconnect();
  }, [threshold]);
  return [ref, v];
}

function useCountUp(target, dur = 1400, active = false) {
  const [v, setV] = useState(0);
  useEffect(() => {
    if (!active) return;
    let s = null;
    const step = ts => { if (!s) s = ts; const p = Math.min((ts-s)/dur,1); setV(Math.round(p*target)); if(p<1) requestAnimationFrame(step); };
    requestAnimationFrame(step);
  }, [active, target, dur]);
  return v;
}

function useWidth() {
  const [w, setW] = useState(typeof window !== "undefined" ? window.innerWidth : 1200);
  useEffect(() => { const h = () => setW(window.innerWidth); window.addEventListener("resize",h); return () => window.removeEventListener("resize",h); }, []);
  return w;
}

// ─── Theme Toggle Button ───────────────────────────────────────────────────────
function ThemeToggle({ dark, onToggle, t }) {
  const [hov, setHov] = useState(false);
  return (
    <button onClick={onToggle}
      onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}
      style={{
        position:"fixed", top:16, right:16, zIndex:1200,
        background: hov ? t.accent : t.toggleBg,
        border:`1px solid ${t.toggleBd}`,
        borderRadius:10, padding:"7px 13px",
        cursor:"pointer", display:"flex", alignItems:"center", gap:7,
        boxShadow: hov ? "0 4px 20px rgba(90,141,181,0.4)" : "0 2px 10px rgba(0,0,0,0.2)",
        transition:"all 0.3s",
      }}>
      <span style={{fontSize:15}}>{dark ? "☀️" : "🌙"}</span>
      <span style={{fontSize:10, color: hov ? "#fff" : t.accentHi, fontWeight:600, letterSpacing:0.5}}>
        {dark ? "CLARO" : "OSCURO"}
      </span>
    </button>
  );
}

// ─── Hamburger Button ─────────────────────────────────────────────────────────
function Hamburger({ open, onClick, t }) {
  return (
    <button onClick={onClick} style={{
      position:"fixed", top:13, left:13, zIndex:2000,
      background:t.accent, border:"none", borderRadius:10,
      width:42, height:42, cursor:"pointer",
      display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:5,
      boxShadow:"0 4px 16px rgba(0,0,0,0.4)", transition:"all 0.3s",
    }}>
      {[0,1,2].map(i => (
        <span key={i} style={{
          display:"block", width:20, height:2, background:"#fff", borderRadius:2,
          transform: open ? (i===0?"rotate(45deg) translate(5px,5px)" : i===2?"rotate(-45deg) translate(5px,-5px)":"rotate(0)") : "none",
          opacity: open && i===1 ? 0 : 1,
          transition:"all 0.3s",
        }}/>
      ))}
    </button>
  );
}

// ─── Cert Modal ───────────────────────────────────────────────────────────────
function CertModal({ certKey, onClose, t }) {
  const c = CERTS[certKey] || EDU[certKey];
  const [loaded, setLoaded] = useState(false);
  useEffect(() => { const h = e => { if(e.key==="Escape") onClose(); }; window.addEventListener("keydown",h); return () => window.removeEventListener("keydown",h); }, [onClose]);
  const isUTO = certKey === "UTO";
  return (
    <div onClick={onClose} style={{
      position:"fixed",inset:0,zIndex:9999, background:t.overlay,
      backdropFilter:"blur(14px)", display:"flex", alignItems:"center", justifyContent:"center",
      padding:20, animation:"fadeIn .25s ease",
    }}>
      <div onClick={e=>e.stopPropagation()} style={{
        maxWidth:800, width:"100%", background:t.modalBg,
        borderRadius:16, border:t.card,
        boxShadow:"0 40px 100px rgba(0,0,0,0.6)",
        overflow:"hidden", animation:"slideUp .35s cubic-bezier(.16,1,.3,1)",
      }}>
        {/* Header */}
        <div style={{padding:"16px 22px", borderBottom:t.card, background:t.summaryBg, display:"flex", justifyContent:"space-between", alignItems:"flex-start"}}>
          <div>
            <div style={{fontSize:13,fontWeight:700,color:t.name,fontFamily:"'Playfair Display',serif",marginBottom:3}}>{c.label}</div>
            <div style={{fontSize:10,color:t.accent}}>{c.issuer}</div>
            <div style={{fontSize:9,color:t.muted,marginTop:2}}>📅 {c.date}</div>
          </div>
          <button onClick={onClose} style={{
            background:"rgba(90,141,181,0.15)",border:"1px solid rgba(90,141,181,0.3)",
            borderRadius:8,color:t.accentHi,fontSize:16,width:32,height:32,
            cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",
            flexShrink:0,marginLeft:16,transition:"all .2s",
          }}>✕</button>
        </div>
        {/* Image */}
        <div style={{padding:"18px 22px 8px", display:"flex", justifyContent:"center", alignItems:"center"}}>
          {!loaded && <div style={{height:300,display:"flex",alignItems:"center",justifyContent:"center",color:t.accent}}><div style={{animation:"spin 1s linear infinite",fontSize:28}}>⟳</div></div>}
          <img src={c.img} alt={c.label} onLoad={()=>setLoaded(true)}
            style={{width:isUTO?"75%":"100%",borderRadius:10,display:loaded?"block":"none",boxShadow:"0 8px 32px rgba(0,0,0,0.4)",border:t.card}}/>
        </div>
        <div style={{textAlign:"center",padding:"8px 0 14px",fontSize:9,color:t.muted}}>ESC o click fuera para cerrar</div>
      </div>
    </div>
  );
}

