// ─── Reusable small components ────────────────────────────────────────────────
function SideSection({ title, children }) {
  return (
    <div style={{marginBottom:12}}>
      <div style={{fontSize:9,fontWeight:700,color:"#5a8db5",textTransform:"uppercase",letterSpacing:2,
        marginBottom:10,display:"flex",alignItems:"center",gap:7}}>
        <span style={{flex:1,height:1,background:"linear-gradient(90deg,#5a8db5,transparent)"}}/>
        {title}
        <span style={{flex:1,height:1,background:"linear-gradient(270deg,#5a8db5,transparent)"}}/>
      </div>
      {children}
    </div>
  );
}

function StatNum({ value, suffix, label }) {
  const [ref,vis] = useInView();
  const n = useCountUp(value, 1300, vis);
  return (
    <div ref={ref} style={{textAlign:"center",opacity:vis?1:0,transform:vis?"translateY(0)":"translateY(12px)",transition:"all .7s ease"}}>
      <div style={{fontSize:27,fontWeight:800,color:"#5a8db5",fontFamily:"'Playfair Display',serif",lineHeight:1}}>{n}{suffix}</div>
      <div style={{fontSize:9,color:"#8aafc4",marginTop:3,letterSpacing:1,textTransform:"uppercase"}}>{label}</div>
    </div>
  );
}

function LangBar({ label, pct }) {
  const [ref,vis] = useInView();
  return (
    <div ref={ref} style={{marginBottom:9}}>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
        <span style={{fontSize:12,color:"#e8f0f8"}}>{label}</span>
        <span style={{fontSize:10,color:"#5a8db5"}}>{pct}%</span>
      </div>
      <div style={{height:5,background:"#3d5468",borderRadius:3,overflow:"hidden"}}>
        <div style={{height:"100%",borderRadius:3,background:"linear-gradient(90deg,#5a8db5,#8aafc4)",
          width:vis?`${pct}%`:"0%",transition:"width 1.1s ease .2s",
          boxShadow:vis?"0 0 8px rgba(90,141,181,0.55)":"none"}}/>
      </div>
    </div>
  );
}

function Badge({ label, delay=0, onOpen }) {
  const [ref,vis] = useInView();
  const [hov,setHov] = useState(false);
  return (
    <div ref={ref}
      onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
      onClick={()=>onOpen(label)}
      title={`Ver certificado: ${label}`}
      style={{
        background:hov?"rgba(90,141,181,0.28)":"#3d5468",
        border:`1px solid ${hov?"#8aafc4":"#5a8db5"}`,
        borderRadius:5, padding:"5px 10px",
        fontSize:9.5, color:hov?"#fff":"#8aafc4",
        cursor:"pointer", position:"relative",
        transform:vis?(hov?"translateY(-3px) scale(1.08)":"translateY(0)"):"translateY(8px)",
        opacity:vis?1:0,
        transition:`all .32s ease ${delay}ms`,
        boxShadow:hov?"0 5px 18px rgba(90,141,181,0.35)":"none",
      }}>
      {label}
      <span style={{position:"absolute",top:-4,right:-4,width:7,height:7,borderRadius:"50%",
        background:"#5a8db5",boxShadow:"0 0 5px rgba(90,141,181,0.9)",
        opacity:hov?1:0.55,transition:"opacity .3s"}}/>
    </div>
  );
}

